() => {
  const table = document.querySelector('.bc-table');
  const rows = Array.from(table.querySelectorAll('tbody tr'));
  const targetRow = rows.find(row => row.innerText.includes('borderBoxSize'));
  if (!targetRow) return "Not Found";
  const safariIndex = Array.from(table.querySelectorAll('thead th')).findIndex(th => th.innerText.includes('Safari') && !th.innerText.includes('iOS'));
  const cell = targetRow.cells[safariIndex];
  return cell ? cell.innerText : "Cell Not Found";
}

() => {
  const table = document.querySelector('table');
  const rows = Array.from(document.querySelectorAll('tr'));
  const borderBoxRow = rows.find(r => r.innerText.includes('borderBoxSize'));
  if (!borderBoxRow) return "borderBoxSize row not found";
  return borderBoxRow.innerText;
}
